55	const basePremiums: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	  moonstone: 25,
62	};
63	
64	const PROCESSING_FEE = 5;
65	
66	const BLOCK_SIZE = 3;
67	
68	const BLOCK_OF_THREE_BASE = 60;
69	
70	const componentTypes = new Set(["rune", "moonstone"]);
71	
72	const countByType = (items: QuoteItem[]): Record<string, number> =>
73	  items.reduce<Record<string, number>>((counts, item) => {
74	    counts[item.type] = (counts[item.type] ?? 0) + 1;
75	    return counts;
76	  }, {});
77	
78	const basePremiumFor = (type: string): number => {
79	  if (!(type in basePremiums)) {
80	    throw new Error(`Unknown item type: ${type}`);
81	  }
82	  return basePremiums[type];
83	};
84	
85	const basePremiumForGroup = (type: string, count: number): number => {
86	  if (componentTypes.has(type) && count === BLOCK_SIZE) {
87	    return BLOCK_OF_THREE_BASE;
88	  }
89	  return basePremiumFor(type) * count;
90	};
91	
92	const CURSE_SURCHARGE_RATE = 0.5;
93	
94	const FIRST_INSURANCE_RATE = 0.1;
95	
96	const HIGH_ENCHANTMENT_THRESHOLD = 5;
97	
98	const HIGH_ENCHANTMENT_RATE = 0.3;
99	
100	const itemBasePremium = (item: QuoteItem): number =>
101	  basePremiumFor(item.type);
102	
103	const isCursed = (item: QuoteItem): boolean => item.cursed === true;
104	
105	const curseSurcharge = (item: QuoteItem): number =>
106	  isCursed(item) ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
107	
108	const enchantmentLevel = (item: QuoteItem): number => item.enchantment ?? 0;
109	
110	const highEnchantmentSurcharge = (item: QuoteItem): number =>
111	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD
112	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_RATE
113	    : 0;
114	
115	const firstInsuranceSurcharge = (item: QuoteItem): number =>
116	  itemBasePremium(item) * FIRST_INSURANCE_RATE;
117	
118	const itemSurcharges = (item: QuoteItem): number =>
119	  curseSurcharge(item) +
120	  highEnchantmentSurcharge(item) +
121	  firstInsuranceSurcharge(item);
122	
123	const sumOfBasePremiums = (items: QuoteItem[]): number => {
124	  const counts = countByType(items);
125	  return Object.entries(counts).reduce(
126	    (sum, [type, count]) => sum + basePremiumForGroup(type, count),
127	    0
128	  );
129	};
130	
131	const sumOfItemSurcharges = (items: QuoteItem[]): number =>
132	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
133	
134	const LOYALTY_YEARS_THRESHOLD = 2;
135	
136	const LOYALTY_DISCOUNT_RATE = 0.2;
137	
138	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
139	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
140	    ? basePremium * LOYALTY_DISCOUNT_RATE
141	    : 0;
142	
143	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
144	
145	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
146	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
147	
148	const quotePremium = (
149	  items: QuoteItem[],
150	  customer: Customer,
151	  isFollowUp: boolean
152	): number => {
153	  const basePremium = sumOfBasePremiums(items);
154	  const surcharges = sumOfItemSurcharges(items);
155	  const discount =
156	    loyaltyDiscount(customer, basePremium) +
157	    followUpDiscount(basePremium, isFollowUp);
158	  return Math.ceil(basePremium + surcharges - discount + PROCESSING_FEE);
159	};
160	
161	const isFollowUpQuote = (steps: Step[], index: number): boolean =>
162	  steps.slice(0, index).some((step) => step.op === "quote");
163	
164	const insuranceValues: Record<string, number> = {
165	  sword: 1000,
166	  amulet: 600,
167	  staff: 800,
168	  potion: 400,
169	  rune: 250,
170	  moonstone: 250,
171	};
172	
173	const DEDUCTIBLE = 100;
174	
175	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
176	
177	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
178	
179	const isHighEnchantmentClaim = (policyItem: QuoteItem | undefined): boolean =>
180	  (policyItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
181	
182	const damagePayout = (damage: Damage, policyItems: QuoteItem[]): number => {
183	  const policyItem = policyItems.find((item) => item.type === damage.itemType);
184	  const reimbursable = isHighEnchantmentClaim(policyItem)
185	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
186	    : damage.amount;
187	  return reimbursable - DEDUCTIBLE;
188	};
189	
190	const CAP_MULTIPLIER = 2;
191	
192	const insuranceCap = (policyItems: QuoteItem[]): number =>
193	  CAP_MULTIPLIER *
194	  policyItems.reduce((sum, item) => sum + insuranceValues[item.type], 0);
195	
196	const totalDamagePayout = (
197	  damages: Damage[],
198	  policyItems: QuoteItem[]
199	): number =>
200	  damages.reduce((total, damage) => total + damagePayout(damage, policyItems), 0);
201	
202	const policyItemsFor = (scenario: Scenario, policy: number): QuoteItem[] =>
203	  (scenario.steps[policy] as QuoteStep).items;
204	
205	const claimResult = (
206	  step: ClaimStep,
207	  policyItems: QuoteItem[],
208	  cap: number
209	): ClaimResult => {
210	  const desiredPayout = Math.floor(
211	    totalDamagePayout(step.incident.damages, policyItems)
212	  );
213	  const payout = Math.min(desiredPayout, cap);
214	  return { payout, remainingCap: cap - payout };
215	};
