217	export function runScenario(scenario: Scenario): ScenarioResult {
218	  const remainingCaps = new Map<number, number>();
219	  const results = scenario.steps.map((step, index): StepResult => {
220	    if (step.op === "claim") {
221	      const policyItems = policyItemsFor(scenario, step.policy);
222	      const cap = remainingCaps.get(step.policy) ?? insuranceCap(policyItems);
223	      const result = claimResult(step, policyItems, cap);
224	      remainingCaps.set(step.policy, result.remainingCap);
225	      return result;
226	    }
227	    const isFollowUp = isFollowUpQuote(scenario.steps, index);
228	    return {
229	      premium: quotePremium(step.items, scenario.customer, isFollowUp),
230	    };
231	  });
232	  return { results };
233	}
